func statusColor(color string) string {
	if len(color) != 7 || color[0] != '#' || strings.IndexFunc(color[1:], func(r rune) bool { return !strings.ContainsRune("0123456789abcdefABCDEF", r) }) != -1 {
		return "#6B7280"
	}
	return color
}

